export type BITool = 'Power BI' | 'Tableau';
export type ScriptLanguage = 'Python' | 'R';

export interface ProjectConfig {
  companyType: string;
  dataFields: string;
  biTool: BITool;
  language: ScriptLanguage;
  industry: string;
}

export interface RoadmapSection {
  title: string;
  content: string;
  codeSnippets?: {
    label: string;
    code: string;
    language: string;
  }[];
}

export interface GeneratedRoadmap {
  title: string;
  executiveSummary: string;
  mlIntegration: RoadmapSection;
  kpiSelection: RoadmapSection;
  dataPreprocessing: RoadmapSection;
  visualLayout: RoadmapSection;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProjectConfig } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async generateRoadmap(config: ProjectConfig): Promise<string> {
    const prompt = `
      Persona: You are an expert Data Scientist and BI Developer specializing in ${config.biTool} and Predictive Analytics.
      Context: I am building a Sales Dashboard for ${config.companyType}. My dataset includes historical data on ${config.dataFields}.
      Task: Create a comprehensive project roadmap for this dashboard.

      Requirements:
      1. Machine Learning Integration: Recommend 2-3 ML models (e.g., Demand Forecasting using Prophet, Customer Segmentation using K-Means, or Churn Prediction) and explain how to implement them via ${config.language} scripts.
      2. KPI Selection: Define the 5 most critical KPIs to track.
      3. Data Preprocessing: Provide a step-by-step guide for cleaning data using ${config.biTool === 'Power BI' ? 'Power Query' : 'Tableau Prep'}.
      4. Visual Layout: Suggest a 3-page dashboard structure.
      5. Format: Output the response as a structured technical guide with Markdown headers, bullet points, and code snippets for any necessary ${config.biTool === 'Power BI' ? 'DAX' : 'Calculated Fields'} or ${config.language} scripts.

      Keep the tone professional, technical, and highly actionable.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          temperature: 0.7,
          topP: 0.95,
          thinkingConfig: { thinkingBudget: 16000 }
        },
      });

      return response.text || "Failed to generate roadmap content.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw new Error("The strategist encountered an error. Please try again.");
    }
  }
}

export const geminiService = new GeminiService();

