import React from 'react';

interface RoadmapViewProps {
  content: string;
}

const RoadmapView: React.FC<RoadmapViewProps> = ({ content }) => {
  // Simple markdown-ish rendering for the UI
  const formatContent = (text: string) => {
    return text.split('\n').map((line, idx) => {
      // Headers
      if (line.startsWith('###')) {
        return <h3 key={idx} className="text-lg font-bold text-slate-800 mt-8 mb-4 border-b pb-2">{line.replace('###', '').trim()}</h3>;
      }
      if (line.startsWith('##')) {
        return <h2 key={idx} className="text-xl font-bold text-indigo-700 mt-10 mb-6">{line.replace('##', '').trim()}</h2>;
      }
      if (line.startsWith('#')) {
        return <h1 key={idx} className="text-3xl font-extrabold text-slate-900 mt-4 mb-8">{line.replace('#', '').trim()}</h1>;
      }
      // Lists
      if (line.trim().startsWith('-') || line.trim().startsWith('*')) {
        return <li key={idx} className="ml-4 text-slate-600 mb-1 leading-relaxed list-disc">{line.replace(/^[*-]/, '').trim()}</li>;
      }
      // Code blocks (simplified handling)
      if (line.startsWith('```')) {
        return null; // Don't render the triple backticks
      }
      // Inline formatting (bold)
      const boldFormatted = line.split(/(\*\*.*?\*\*)/).map((part, i) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={i} className="text-slate-800">{part.slice(2, -2)}</strong>;
        }
        return part;
      });

      return <p key={idx} className="text-slate-600 mb-4 leading-relaxed">{boldFormatted}</p>;
    });
  };

  // More sophisticated rendering would use a markdown library, but we manually format code blocks for visual pop
  const renderSections = () => {
    const sections: React.ReactNode[] = [];
    let currentBlock: string[] = [];
    let inCodeBlock = false;
    let codeLanguage = '';

    const lines = content.split('\n');

    lines.forEach((line, idx) => {
      if (line.startsWith('```')) {
        if (inCodeBlock) {
          // Closing code block
          sections.push(
            <div key={`code-${idx}`} className="my-6 rounded-lg overflow-hidden bg-slate-900 shadow-xl">
              <div className="bg-slate-800 px-4 py-1 flex justify-between items-center text-[10px] text-slate-400 font-mono uppercase tracking-widest">
                <span>{codeLanguage || 'code'}</span>
                <button 
                   onClick={() => navigator.clipboard.writeText(currentBlock.join('\n'))}
                   className="hover:text-white transition-colors"
                >
                  Copy
                </button>
              </div>
              <pre className="p-4 overflow-x-auto text-sm text-indigo-300 code-font">
                {currentBlock.join('\n')}
              </pre>
            </div>
          );
          currentBlock = [];
          inCodeBlock = false;
        } else {
          // Opening code block
          inCodeBlock = true;
          codeLanguage = line.replace('```', '').trim();
        }
      } else if (inCodeBlock) {
        currentBlock.push(line);
      } else {
        // Normal text rendering logic
        if (line.trim() === '') return;

        if (line.startsWith('#')) {
          const level = line.match(/^#+/)?.[0].length || 1;
          const text = line.replace(/^#+/, '').trim();
          if (level === 1) sections.push(<h1 key={idx} className="text-4xl font-black text-slate-900 mt-12 mb-8 tracking-tight">{text}</h1>);
          else if (level === 2) sections.push(<h2 key={idx} className="text-2xl font-bold text-indigo-700 mt-12 mb-6 border-l-4 border-indigo-600 pl-4">{text}</h2>);
          else sections.push(<h3 key={idx} className="text-xl font-bold text-slate-800 mt-8 mb-4">{text}</h3>);
        } else if (line.trim().startsWith('-') || line.trim().startsWith('*')) {
          sections.push(<li key={idx} className="ml-6 text-slate-600 mb-2 list-disc leading-relaxed">{line.replace(/^[*-]/, '').trim()}</li>);
        } else {
          // Basic paragraph with bold support
          const boldParts = line.split(/(\*\*.*?\*\*)/).map((p, i) => {
            if (p.startsWith('**') && p.endsWith('**')) return <strong key={i} className="text-slate-900 font-semibold">{p.slice(2, -2)}</strong>;
            return p;
          });
          sections.push(<p key={idx} className="text-slate-600 mb-4 leading-relaxed text-lg">{boldParts}</p>);
        }
      }
    });

    return sections;
  };

  return (
    <div className="max-w-4xl mx-auto py-12 px-8 bg-white shadow-sm border border-slate-100 rounded-xl my-8">
      <div className="mb-12 border-b border-slate-100 pb-8 flex justify-between items-start">
        <div>
          <span className="inline-block px-3 py-1 bg-indigo-100 text-indigo-700 text-xs font-bold rounded-full uppercase tracking-wider mb-4">Strategic Roadmap</span>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Technical Implementation Guide</h1>
        </div>
        <button 
           onClick={() => window.print()}
           className="px-4 py-2 border border-slate-200 rounded-lg text-sm font-medium text-slate-600 hover:bg-slate-50 transition-colors flex items-center gap-2"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z" />
          </svg>
          Export PDF
        </button>
      </div>
      <div className="prose prose-slate max-w-none">
        {renderSections()}
      </div>
    </div>
  );
};

export default RoadmapView;

import React, { useState, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import RoadmapView from './components/RoadmapView';
import { ProjectConfig } from './types';
import { geminiService } from './services/geminiService';

const App: React.FC = () => {
  const [config, setConfig] = useState<ProjectConfig>({
    companyType: '',
    dataFields: '',
    biTool: 'Power BI',
    language: 'Python',
    industry: 'Retail'
  });

  const [roadmap, setRoadmap] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleConfigChange = useCallback((updates: Partial<ProjectConfig>) => {
    setConfig(prev => ({ ...prev, ...updates }));
  }, []);

  const generateRoadmap = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const result = await geminiService.generateRoadmap(config);
      setRoadmap(result);
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar 
        config={config} 
        onChange={handleConfigChange} 
        onGenerate={generateRoadmap}
        isLoading={isLoading}
      />

      <main className="flex-1 overflow-y-auto px-6 pb-20">
        {!roadmap && !isLoading && !error && (
          <div className="flex flex-col items-center justify-center h-full max-w-2xl mx-auto text-center py-20">
            <div className="w-20 h-20 bg-indigo-100 rounded-3xl flex items-center justify-center text-indigo-600 mb-8 shadow-inner">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
              </svg>
            </div>
            <h2 className="text-3xl font-bold text-slate-900 mb-4">Welcome to the Architect's Studio</h2>
            <p className="text-slate-600 text-lg leading-relaxed">
              Design professional-grade BI roadmaps in seconds. Configure your project parameters on the left and let our AI Data Science persona craft a comprehensive technical guide including ML integration, KPIs, and visualization layouts.
            </p>
            <div className="grid grid-cols-3 gap-6 mt-12 w-full">
              <div className="p-4 bg-white rounded-xl border border-slate-200 shadow-sm">
                <p className="text-indigo-600 font-bold text-lg mb-1">ML Ready</p>
                <p className="text-xs text-slate-500">Forecasting, Clustering & Regression scripts included.</p>
              </div>
              <div className="p-4 bg-white rounded-xl border border-slate-200 shadow-sm">
                <p className="text-indigo-600 font-bold text-lg mb-1">Tool Focused</p>
                <p className="text-xs text-slate-500">Customized DAX or Calculated Fields logic.</p>
              </div>
              <div className="p-4 bg-white rounded-xl border border-slate-200 shadow-sm">
                <p className="text-indigo-600 font-bold text-lg mb-1">Visual Design</p>
                <p className="text-xs text-slate-500">Page-by-page UX structure for executive buy-in.</p>
              </div>
            </div>
          </div>
        )}

        {isLoading && (
          <div className="flex flex-col items-center justify-center h-full py-40">
            <div className="relative">
              <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-2 h-2 bg-indigo-600 rounded-full animate-ping"></div>
              </div>
            </div>
            <p className="mt-8 text-slate-500 font-medium animate-pulse">Consulting the Expert Data Scientist...</p>
            <p className="text-slate-400 text-sm mt-2">Processing dataset fields and optimizing ML models.</p>
          </div>
        )}

        {error && (
          <div className="max-w-2xl mx-auto mt-20 p-6 bg-red-50 border border-red-100 rounded-xl flex items-start gap-4 shadow-sm">
            <div className="w-10 h-10 bg-red-100 rounded-full flex-shrink-0 flex items-center justify-center text-red-600">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <div>
              <h3 className="font-bold text-red-800 text-lg">Strategist Error</h3>
              <p className="text-red-700 mt-1">{error}</p>
              <button 
                onClick={generateRoadmap}
                className="mt-4 px-4 py-2 bg-red-600 text-white rounded-lg text-sm font-semibold hover:bg-red-700 transition-all"
              >
                Try Again
              </button>
            </div>
          </div>
        )}

        {roadmap && !isLoading && !error && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <RoadmapView content={roadmap} />
            <div className="flex justify-center py-10">
              <button 
                onClick={() => setRoadmap(null)}
                className="text-slate-400 hover:text-slate-600 transition-colors text-sm font-medium flex items-center gap-2"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                </svg>
                Reset & Start New Project
              </button>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;
